<style scoped>
.skills-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 10px;
}
.skill-card {
  background: var(--bg-panel);
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius-sm);
  aspect-ratio: 1;
  display: flex; align-items: center; justify-content: center;
  position: relative;
  transition: border-color .2s, transform .2s;
}
.skill-card:hover { border-color: var(--mint-dim); transform: translateY(-3px); }
.skill-icon { width: 28px; height: 28px; color: var(--text-secondary); transition: color .2s; }
.skill-icon :deep(svg) { width: 100%; height: 100%; }
.skill-card:hover .skill-icon { color: var(--mint); }
.skill-name {
  position: absolute; bottom: -26px; left: 50%; transform: translateX(-50%);
  font-size: 10px; color: var(--text-tertiary); white-space: nowrap;
  opacity: 0; transition: opacity .2s;
}
.skill-card:hover .skill-name { opacity: 1; }

@media (max-width: 768px) { .skills-grid { grid-template-columns: repeat(3, 1fr); } }
@media (max-width: 480px) { .skills-grid { grid-template-columns: repeat(2, 1fr); } }
</style>
